function SA_Mechanisms(sites,L,M,kw,c,nCh)
    # Using the specific keyword (kw), program will build an MPO which is generated by autoMPO
    # L: length of MPS
    # M: Maximum number of molecules that can exist for a species.
    # kw: represents the effective Hamiltonian to be built.
    # c: Vector of stochastic rate coefficients
    # nCh: Occupation number of chemostated species [Fuel,Waste]
# ==========================================================================================
    ampo = AutoMPO();
    # ̂n = [1,2,3,4] = [M,M*,A_2*,A_2]

    if cmp(kw,"Energy_Storage") == 0
        # F + M -> M*
        ampo .+=  c[1]*nCh[1],"a",1,"adag",2
        ampo .+= -c[1]*nCh[1],"adag",1,"a",1,"ProjMc",2

        # M* -> F + M
        ampo .+=  c[2],"a",2,"adag",1
        ampo .+= -c[2],"adag",2,"a",2,"ProjMc",1

        # M + W -> M*
        ampo .+= c[3]*nCh[2],"a",1,"adag",2
        ampo .+= -c[3]*nCh[2],"adag",1,"a",1,"ProjMc",2

        # M* -> M + W
        ampo .+=  c[4],"a",2,"adag",1
        ampo .+= -c[4],"adag",2,"a",2,"ProjMc",1
      
        # 2M* -> A*_2
        ampo .+= c[5],"a",2,"a",2,"adag",3
        ampo .+= -c[5],"adag",2,"adag",2,"a",2,"a",2,"ProjMc",3
        
        # A*_2 -> 2M*
        ampo .+= c[6],"a",3,"adag",2,"adag",2
        ampo .+= -c[6],"adag",3,"a",3,"ProjMc2",2
        
        # A*_2 -> A_2 + 2F
        ampo .+=  c[7],"a",3,"adag",4
        ampo .+= -c[7],"adag",3,"a",3,"ProjMc",4

        # 2F + A_2 -> A*_2
        ampo .+= c[8]*nCh[1]*(nCh[1]-1),"a",4,"adag",3
        ampo .+= -c[8]*nCh[1]*(nCh[1]-1),"adag",4,"a",4,"ProjMc",3

        # A*_2 -> A_2 + 2W
        ampo .+= c[9],"a",3,"adag",4
        ampo .+= -c[9],"adag",3,"a",3,"ProjMc",4

        # 2W + A_2 ->  A*_2
        ampo .+= c[10]*nCh[2]*(nCh[2]-1),"a",4,"adag",3
        ampo .+= -c[10]*nCh[2]*(nCh[2]-1),"adag",4,"a",4,"ProjMc",3


        return MPO(ampo,sites);
    end

    if cmp(kw,"EStorage_NoEscRate") == 0
        # Each entry in HOPerators is an MPO for the single reaction without a diagonal. This was more efficient than other data structures
        HOperators = []
         # F + M -> M*
         ampo1 = AutoMPO();
         ampo1 .+= c[1]*nCh[1],"a",1,"adag",2
         push!(HOperators,MPO(ampo1,sites))

        # M* -> F + M
        ampo2 = AutoMPO();
        ampo2 .+=  c[2],"a",2,"adag",1
        push!(HOperators,MPO(ampo2,sites))

        # M + W -> M*
        ampo3 = AutoMPO();
        ampo3 .+= c[3]*nCh[2],"a",1,"adag",2
        push!(HOperators,MPO(ampo3,sites))

        # M* -> M + W
        ampo4 = AutoMPO();
        ampo4 .+=  c[4],"a",2,"adag",1
        push!(HOperators,MPO(ampo4,sites))

        # 2M* -> A*_2
        ampo5 = AutoMPO();
        ampo5 .+= c[5],"a",2,"a",2,"adag",3
        push!(HOperators,MPO(ampo5,sites))

        # A*_2 -> 2M*
        ampo6 = AutoMPO();
        ampo6 .+= c[6],"a",3,"adag",2,"adag",2
        push!(HOperators,MPO(ampo6,sites))

        # A*_2 -> A_2 + 2F
        ampo7 = AutoMPO();
        ampo7 .+=  c[7],"a",3,"adag",4
        push!(HOperators,MPO(ampo7,sites))

        # 2F + A_2 -> A*_2
        ampo8 = AutoMPO();
        ampo8 .+= c[8]*nCh[1]*(nCh[1]-1),"a",4,"adag",3
        push!(HOperators,MPO(ampo8,sites))
        
        # A*_2 -> A_2 + 2W
        ampo9 = AutoMPO();
        ampo9 .+= c[9],"a",3,"adag",4
        push!(HOperators,MPO(ampo9,sites))

        # 2W + A_2 ->  A*_2
        ampo10 = AutoMPO()
        ampo10 .+= c[10]*nCh[2]*(nCh[2]-1),"a",4,"adag",3
        push!(HOperators,MPO(ampo10,sites))
        return HOperators
    end
# Build individual MPO operators for each reaction in order to exactly calculate the EPR
    if cmp(kw,"H1f") == 0
        # F + M -> M*
        ampo .+=  c[1]*nCh[1],"a",1,"adag",2
        ampo .+= -c[1]*nCh[1],"adag",1,"a",1,"ProjMc",2
        return MPO(ampo,sites);
    end
    if cmp(kw,"H1r") == 0 
        # M* -> F + M
        ampo .+=  c[2],"a",2,"adag",1
        ampo .+= -c[2],"adag",2,"a",2,"ProjMc",1
        return MPO(ampo,sites);
    end
     if cmp(kw,"H2f") == 0 
        # M + W -> M*
        ampo .+= c[3]*nCh[2],"a",1,"adag",2
        ampo .+= -c[3]*nCh[2],"adag",1,"a",1,"ProjMc",2
        return MPO(ampo,sites);
    end
     if cmp(kw,"H2r") == 0 
        # M* -> M + W
        ampo .+=  c[4],"a",2,"adag",1
        ampo .+= -c[4],"adag",2,"a",2,"ProjMc",1
        return MPO(ampo,sites);
    end
     if cmp(kw,"H3f") == 0 
        # 2M* -> A*_2
        ampo .+= c[5],"a",2,"a",2,"adag",3
        ampo .+= -c[5],"adag",2,"adag",2,"a",2,"a",2,"ProjMc",3
        return MPO(ampo,sites);
    end
     if cmp(kw,"H3r") == 0 
        # A*_2 -> 2M*
        ampo .+= c[6],"a",3,"adag",2,"adag",2
        ampo .+= -c[6],"adag",3,"a",3,"ProjMc2",2
        return MPO(ampo,sites);
    end
     if cmp(kw,"H4f") == 0 
        # A*_2 -> A_2 + 2F
        ampo .+=  c[7],"a",3,"adag",4
        ampo .+= -c[7],"adag",3,"a",3,"ProjMc",4
        return MPO(ampo,sites);
    end
     if cmp(kw,"H4r") == 0 
        # 2F + A_2 -> A*_2
        ampo .+= c[8]*nCh[1]*(nCh[1]-1),"a",4,"adag",3
        ampo .+= -c[8]*nCh[1]*(nCh[1]-1),"adag",4,"a",4,"ProjMc",3
        return MPO(ampo,sites);
    end
    if cmp(kw,"H5f") == 0 
         # A*_2 -> A_2 + 2W
        ampo .+= c[9],"a",3,"adag",4
        ampo .+= -c[9],"adag",3,"a",3,"ProjMc",4
        return MPO(ampo,sites);
    end
    if cmp(kw,"H5r") == 0
        # 2W + A_2 ->  A*_2
        ampo .+= c[10]*nCh[2]*(nCh[2]-1),"a",4,"adag",3
        ampo .+= -c[10]*nCh[1]*(nCh[2]-1),"adag",4,"a",4,"ProjMc",3
    end
end





